#include <openssl/malloc.h>

/**
 * @param pkey     The private key (EVP_PKEY*)
 * @param digest   The pre-computed message digest
 * @param digest_len The length of the digest
 * @param sig_out  Pointer to a buffer that will hold the signature
 * @param sig_len  Pointer to the length of the signature (in/out)
 * 
 * @return 1 on success, 0 on failure
 */
int sign_digest_one_shot(EVP_PKEY *pkey, 
                         const unsigned char *digest, 
                         size_t digest_len, 
                         unsigned char **sig_out, 
                         size_t *sig_len) 
{
    // 1. Determine the required buffer size for the signature
    // Calling EVP_PKEY_sign with NULL for the signature buffer returns the required length.
    if (EVP_PKEY_sign(pkey, NULL, sig_len, digest, digest_len) <= 0) {
        return 0;
    }

    // 2. Allocate memory for the signature
    *sig_out = OPENSSL_malloc(*sig_len);

