#include <stdio.h>
#include <string.h>
#include <openssl/evp.h>
#include <openssl/params.h>
#include <openssl/mac.h>

int main() {
    const char *msg = "The quick brown fox jumps over the lazy dog";
    const unsigned char *key = (const unsigned char *)"secret_key";
    size_t key_len = strlen((char *)key);
    size_t msg_len = strlen(msg);
    unsigned char out[EVP_MAX_MD_SIZE];
    size_t out_len;

    EVP_MAC *mac = NULL;
    EVP_MAC_CTX *ctx = NULL;
    OSSL_PARAM *params = NULL;

    // 1. Fetch the HMAC implementation
    mac = EVP_MAC_fetch(NULL, "HMAC", NULL);
    if (mac == NULL) goto err;

    // 2. Create a new MAC context
    ctx = EVP_MAC_CTX_new(mac);
    if (ctx == NULL) goto err;

    // 3. Initialize the context and set the key via OSSL_PARAM
    // For HMAC, the parameter name is "key"
    params = OSSL_PARAM_construct8_char_string("key", key, key_len);
    OSSL_PARAM *param_array[2];
    param_array[0] = params;
    param_array[1] = OSSL_PARAM_construct_end();

    if (EVP_MAC_init(ctx, param_array) != 1) goto err;

    // 4. Update with the message
    if (EVP_MAC_update(ctx, (unsigned char *)msg, msg_len) != 1) goto err;

    // 5. Finalize to get the digest
    if (EVP_MAC_final(ctx, out, &out_len, sizeof(out)) != 1) goto err;

    // Print result
    printf("HMAC-SHA256: ");
    for (size_t i = 0; i < out_len; i++) printf("%02x", out[i]);
    printf("\n");

    // Cleanup
    EVP_MAC_CTX_free(ctx);
    EVP_MAC_free(mac);
    return 0;

err:
    if (ctx) EVP_MAC_CTX_free(ctx);
    if (mac) EVP_MAC_free(mac);
    return 1;
}
```

