#include <openssl/evp.h>
#include <openssl/bn.h>

/**
 * Gets the RSA modulus (n) from an EVP_PKEY using the OpenSSL 3.0 parameter API.
 * 
 * @param pkey The EVP_PKEY containing the RSA key.
 * @param n    Pointer to a BIGNUM to store the modulus.
 * @return 1 on success, 0 or negative on failure.
 */
int get_rsa_modulus(EVP_PKEY *pkey, BIGNUM **n) {
    if (pkey == NULL || n == NULL) {
        return 0;
    }
    // EVP_PKEY_get_bn_param returns a pointer to the internal BIGNUM.
    // The caller does not own this pointer and must not free it.
    return EVP_PKEY_get_bn_param(pkey, "n", n);
}
